1	type Item = { type: string };
2	type Step = { op: "quote"; items: Item[] };
3	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
4	
5	const PROCESSING_FEE = 5;
6	const FIRST_INSURANCE_RATE = 0.1;
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	};
13	
14	const basePremiumFor = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
15	
16	const itemPremium = (item: Item): number => {
17	  const base = basePremiumFor(item);
18	  return base + base * FIRST_INSURANCE_RATE;
19	};
20	
21	const quotePremium = (items: Item[]): number => {
22	  const itemsTotal = items.reduce((total, item) => total + itemPremium(item), 0);
23	  return Math.ceil(itemsTotal + PROCESSING_FEE);
24	};
25	
26	export const runScenario = (scenario: Scenario): { results: Array<{ premium: number }> } => ({
27	  results: scenario.steps.map((step) => ({ premium: quotePremium(step.items) })),
28	});
